body:
Carrying the conversation over from #6587 into a new issue.  @paul-demo 

As discussed, uncommenting the two lines below is a syntax error.

Thanks,
-e-

```
interface x_if #(
   parameter type rq_t = logic
   ,parameter int param0 = 0
)();
endinterface

module x_top #()
(
   x_if x_io
);
   //localparam type my_rq_t = x_io.rq_t;
   //my_rq_t rq;

   localparam int p0 = x_io.param0;
endmodule

module top();

   typedef struct packed {
      logic vld;
      logic [3:0] cmd; 
   } rq_t;

   x_if #(
      .rq_t(rq_t)
      ,.param0(100)
   ) if0();

   x_top x_top0(
      .x_io(if0)
   );

endmodule
```

